function GPUMonitorWidget() {
  const [stats, setStats] = React.useState({ temp: 62, load: 45, memory: 78 });

  React.useEffect(() => {
    const id = setInterval(() => {
      setStats({
        temp: Math.min(100, Math.max(30, stats.temp + (Math.random() * 10 - 5))),
        load: Math.min(100, Math.max(0, stats.load + (Math.random() * 20 - 10))),
        memory: Math.min(100, Math.max(20, stats.memory + (Math.random() * 10 - 5)))
      });
    }, 3000);
    return () => clearInterval(id);
  }, [stats]);

  function bar(label, value, color) {
    return (
      <div style={{ marginBottom: 14 }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, marginBottom: 4 }}>
          <span>{label}</span>
          <span>{value.toFixed(1)}%</span>
        </div>
        <div style={{ height: 10, background: '#1e293b', borderRadius: 5, overflow: 'hidden' }}>
          <div style={{ width: value + '%', height: '100%', background: color, transition: 'width 0.5s ease' }} />
        </div>
      </div>
    );
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%' }}>
      <h3 style={{ margin: 0, marginBottom: 16 }}>GPU Monitor</h3>
      {bar('Temperature', stats.temp, '#ef4444')}
      {bar('Load', stats.load, '#3b82f6')}
      {bar('Memory', stats.memory, '#22c55e')}
      <div style={{ marginTop: 8, fontSize: 11, color: '#64748b' }}>GPU 0: NVIDIA GeForce RTX 4090</div>
    </div>
  );
}
render(<GPUMonitorWidget/>);
